SELECT ?station ?stationLabel WHERE {
  wd:Q1055811 wdt:P527 ?station.
  ?station wdt:P131 wd:Q505.
  OPTIONAL { ?station rdfs:label ?stationLabel . FILTER (LANG(?stationLabel) = "en") }
}

SELECT ?station ?stationLabel WHERE {
  wd:Q1055811 wdt:P527 ?station.
  OPTIONAL { ?station rdfs:label ?stationLabel . FILTER (LANG(?stationLabel) = "en") }
}

SELECT ?station ?stationLabel WHERE {
  wd:Q1055811 wdt:P527 ?station.
  ?station rdfs:label ?stationLabel.
  FILTER (LANG(?stationLabel) = "en")
  FILTER (CONTAINS(LCASE(STR(?stationLabel)), "newark"))
}
